const payload = $input.first().json.payload || $input.first().json;

const pendingReviews = (payload.pending_chief_architect_reviews || []).length;
const blockedMissions = (payload.blocked_missions || []).length;
const pendingApprovals = (payload.pending_buck_approvals || []).length;
const pendingCodeTasks = (payload.pending_code_tasks || []).length;
const pendingBcTasks = (payload.pending_bc_tasks || []).length;

const staticData = $getWorkflowStaticData('global');
const lastSignature = staticData.lastSignature || '';
const signature = `${pendingReviews}-${blockedMissions}-${pendingApprovals}-${pendingCodeTasks}-${pendingBcTasks}`;

const hasWork = pendingReviews > 0 || blockedMissions > 0 || pendingApprovals > 0;
const isNew = signature !== lastSignature;

if (hasWork) {
  staticData.lastSignature = signature;
} else if (lastSignature !== '') {
  staticData.lastSignature = '';
}

const lines = [];
if (pendingApprovals > 0) lines.push(`${pendingApprovals} pending Buck approval(s)`);
if (pendingReviews > 0) lines.push(`${pendingReviews} pending Chief Architect review message(s) for GBT`);
if (blockedMissions > 0) lines.push(`${blockedMissions} blocked mission(s): ` + (payload.blocked_missions || []).map(m => m.title).join(', '));
if (pendingCodeTasks > 0) lines.push(`${pendingCodeTasks} pending Claude Code task(s)`);
if (pendingBcTasks > 0) lines.push(`${pendingBcTasks} pending Browser Claude task(s)`);

return [{
  json: {
    should_notify: hasWork && isNew,
    source_agent: 'n8n',
    target_agent: 'buck',
    message_type: 'review_required',
    title: 'Team backlog check - GBT/BC need a session opened',
    body: (lines.length ? lines.join(' | ') : 'Backlog pending') + '. Neither GBT nor Browser Claude can self-check - open a chat with either to have them pick this up.',
    priority: blockedMissions > 0 ? 'high' : 'medium',
    skip_notify: false,
  }
}];
